input.command:
agent-browser eval "(() => {
  const points = Array.from(document.querySelectorAll('.mark-symbol.role-mark path'));
  const colors = points.map(p => p.getAttribute('fill'));
  const colorCounts = {};
  colors.forEach(c => {
    colorCounts[c] = (colorCounts[c] || 0) + 1;
  });
  return {
    totalPoints: points.length,
    colorCounts: colorCounts
  };
})()"

